import { BrowserRouter, Routes, Route, Navigate } from 'react-router-dom';
import { useSelector } from 'react-redux';
import Login from './pages/Login';
import Dashboard from './pages/Dashboard';
import ManageUsers from './pages/ManageUsers';
import GradeStudents from './pages/GradeStudents';
import StudentGrades from './pages/StudentGrades';
import Navbar from './components/Navbar';

const App = () => {
  const user = useSelector((state) => state.auth.user);

  return (
    <BrowserRouter>
      <Navbar />
      <Routes>
        <Route path="/" element={<Dashboard />} />
        <Route path="/login" element={<Login />} />
        {user?.role === 'admin' && <Route path="/manage-users" element={<ManageUsers />} />}
        {user?.role === 'teacher' && <Route path="/grade" element={<GradeStudents />} />}
        {user?.role === 'student' && <Route path="/my-grades" element={<StudentGrades />} />}
        <Route path="*" element={<Navigate to="/" />} />
      </Routes>
    </BrowserRouter>
  );
};

export default App;
